import type { IEngineConfig } from '../types/engine.g.js';

/** Builder for configuring and creating a GoudGame instance with provider selection. */
export class EngineConfig implements IEngineConfig {
  private native: any;

  constructor() {
    this.native = new (getNativeBindings().NativeEngineConfig)();
  }

  /** Sets the window title */
  setTitle(title: string): EngineConfig {
    this.native.setTitle(title);
    return this;
  }

  /** Sets the window size in pixels */
  setSize(width: number, height: number): EngineConfig {
    this.native.setSize(width, height);
    return this;
  }

  /** Enables or disables vertical sync */
  setVsync(enabled: boolean): EngineConfig {
    this.native.setVsync(enabled);
    return this;
  }

  /** Sets the fullscreen mode (0=Windowed, 1=Borderless, 2=Exclusive) */
  setFullscreen(mode: number): EngineConfig {
    this.native.setFullscreen(mode);
    return this;
  }

  /** Sets the target frames per second */
  setTargetFps(fps: number): EngineConfig {
    this.native.setTargetFps(fps);
    return this;
  }

  /** Enables or disables the FPS debug overlay */
  setFpsOverlay(enabled: boolean): EngineConfig {
    this.native.setFpsOverlay(enabled);
    return this;
  }

  /** Enables or disables physics debug visualization */
  setPhysicsDebug(enabled: boolean): EngineConfig {
    this.native.setPhysicsDebug(enabled);
    return this;
  }

  /** Selects the 2D physics backend used by the built game */
  setPhysicsBackend2D(backend: PhysicsBackend2D): EngineConfig {
    this.native.setPhysicsBackend2D(backend);
    return this;
  }

  /** Selects the native render backend used by the built game */
  setRenderBackend(backend: RenderBackendKind): EngineConfig {
    this.native.setRenderBackend(backend);
    return this;
  }

  /** Selects the native window backend used by the built game */
  setWindowBackend(backend: WindowBackendKind): EngineConfig {
    this.native.setWindowBackend(backend);
    return this;
  }

  /** Configures debugger runtime startup for the created game. */
  setDebugger(debuggerConfig: IDebuggerConfig): EngineConfig {
    this.native.setDebugger({
      enabled: debuggerConfig.enabled,
      publishLocalAttach: debuggerConfig.publishLocalAttach,
      routeLabel: debuggerConfig.routeLabel,
    });
    return this;
  }

  /** Consumes the config and creates a windowed GoudGame instance */
  build(): GoudGame {
    const ctx = this.native.build();
    const game = Object.create(GoudGame.prototype);
    game.native = ctx;
    (game as any).preloadedTextures = new Map<string, number>();
    (game as any).preloadedFonts = new Map<string, number>();
    (game as any).texturePathByHandle = new Map<number, string>();
    (game as any).fontPathByHandle = new Map<number, string>();
    (game as any).preloadInFlight = false;
    return game;
  }

  /** Frees the config without building */
  destroy(): void {
    this.native.destroy();
  }

}

function toNativeUiNodeId(nodeId: UiNodeId): number {
  return typeof nodeId === 'bigint' ? Number(nodeId) : nodeId;
}

export class UiManager implements IUiManager {
  private native: any;

  constructor() {
    this.native = new (getNativeBindings().UiManager)();
  }

  /** Runs the UI layout update tick */
  update(): void {
    this.native.update();
  }

  /** Renders the UI tree */
  render(): void {
    this.native.render();
  }

  /** Returns the number of live nodes in the UI tree */
  nodeCount(): number {
    return this.native.nodeCount();
  }

  /** Creates a new UI node with the given component type (0=Panel, -1=none) */
  createNode(componentType: number): UiNodeId {
    return this.native.createNode(componentType);
  }

  /** Removes a UI node and its subtree */
  removeNode(nodeId: UiNodeId): number {
    return this.native.removeNode(toNativeUiNodeId(nodeId));
  }

  /** Sets or clears the parent of a UI node (use u64.MAX to detach) */
  setParent(childId: UiNodeId, parentId: UiNodeId): number {
    return this.native.setParent(toNativeUiNodeId(childId), toNativeUiNodeId(parentId));
  }

  /** Returns the parent node ID, or u64.MAX if none */
  getParent(nodeId: UiNodeId): UiNodeId {
    return this.native.getParent(toNativeUiNodeId(nodeId)) as UiNodeId;
  }

  /** Returns the number of children of a node */
  getChildCount(nodeId: UiNodeId): number {
    return this.native.getChildCount(toNativeUiNodeId(nodeId));
  }

  /** Returns the child node ID at a given index, or u64.MAX if out of bounds */
  getChildAt(nodeId: UiNodeId, index: number): UiNodeId {
    return this.native.getChildAt(toNativeUiNodeId(nodeId), index) as UiNodeId;
  }

  /** Sets or clears the widget component on an existing UI node */
  setWidget(nodeId: UiNodeId, widgetKind: number): number {
    return this.native.setWidget(toNativeUiNodeId(nodeId), widgetKind);
  }

  /** Applies per-node style overrides using a C-safe style payload */
  setStyle(nodeId: UiNodeId, style: IUiStyle): number {
    return this.native.setStyle(toNativeUiNodeId(nodeId), style);
  }

  /** Sets or creates a label widget and updates its text */
  setLabelText(nodeId: UiNodeId, text: string): number {
    return this.native.setLabelText(toNativeUiNodeId(nodeId), text);
  }

  /** Sets or creates a button widget and updates its enabled state */
  setButtonEnabled(nodeId: UiNodeId, enabled: boolean): number {
    return this.native.setButtonEnabled(toNativeUiNodeId(nodeId), enabled);
  }

  /** Sets or creates an image widget and updates its texture path */
  setImageTexturePath(nodeId: UiNodeId, path: string): number {
    return this.native.setImageTexturePath(toNativeUiNodeId(nodeId), path);
  }

  /** Sets or creates a slider widget and updates range/value/enabled */
  setSlider(nodeId: UiNodeId, min: number, max: number, value: number, enabled: boolean): number {
    return this.native.setSlider(toNativeUiNodeId(nodeId), min, max, value, enabled);
  }

  /** Set absolute screen-space position for a UI node. Switches the node to absolute positioning mode. */
  setNodePosition(nodeId: UiNodeId, x: number, y: number): number {
    return this.native.setNodePosition(toNativeUiNodeId(nodeId), x, y);
  }

  /** Set visibility for a UI node. Hidden nodes are not rendered. */
  setNodeVisible(nodeId: UiNodeId, visible: boolean): number {
    return this.native.setNodeVisible(toNativeUiNodeId(nodeId), visible);
  }

  /** Returns the number of UI events captured in the latest update tick */
  eventCount(): number {
    return this.native.eventCount();
  }

  /** Reads one captured UI event by index */
  eventRead(index: number): IUiEvent | null {
    return this.native.eventRead(index) as unknown as IUiEvent | null;
  }

  createPanel(): UiNodeId {
    return this.createNode(0);
  }

  createLabel(text: string): UiNodeId {
    const nodeId = this.createNode(2);
    this.setLabelText(nodeId, text);
    return nodeId;
  }

  createButton(enabled: boolean = true): UiNodeId {
    const nodeId = this.createNode(1);
    this.setButtonEnabled(nodeId, enabled);
    return nodeId;
  }

  createImage(path: string): UiNodeId {
    const nodeId = this.createNode(3);
    this.setImageTexturePath(nodeId, path);
    return nodeId;
  }

  createSlider(min: number, max: number, value: number, enabled: boolean = true): UiNodeId {
    const nodeId = this.createNode(4);
    this.setSlider(nodeId, min, max, value, enabled);
    return nodeId;
  }
}
